namespace Payments;

/// <summary>
/// Processes credit-card charges, refunds, and incoming payment-provider webhooks.
/// Delegates to an <see cref="IPaymentProvider"/> for the actual payment operations.
/// </summary>
public sealed class PaymentGateway
{
    private readonly IPaymentProvider _provider;

    public PaymentGateway(IPaymentProvider provider)
    {
        _provider = provider ?? throw new ArgumentNullException(nameof(provider));
    }

    public async Task<ChargeResult> ChargeAsync(string cardToken, decimal amount)
    {
        ArgumentException.ThrowIfNullOrWhiteSpace(cardToken);

        if (amount <= 0)
            throw new ArgumentOutOfRangeException(nameof(amount), "Amount must be positive.");

        return await _provider.CreateChargeAsync(cardToken, amount);
    }

    public async Task<RefundResult> RefundAsync(string chargeId)
    {
        ArgumentException.ThrowIfNullOrWhiteSpace(chargeId);

        return await _provider.CreateRefundAsync(chargeId);
    }

    public async Task<WebhookResult> ProcessWebhookAsync(string payload, string signature)
    {
        ArgumentException.ThrowIfNullOrWhiteSpace(payload);
        ArgumentException.ThrowIfNullOrWhiteSpace(signature);

        if (!_provider.VerifySignature(payload, signature))
            return new WebhookResult(Handled: false, EventType: null);

        var eventType = _provider.ParseEventType(payload);
        await _provider.HandleEventAsync(eventType, payload);

        return new WebhookResult(Handled: true, EventType: eventType);
    }
}

public record ChargeResult(string ChargeId, bool Success);
public record RefundResult(string RefundId, bool Success);
public record WebhookResult(bool Handled, string? EventType);

/// <summary>
/// Abstraction over the external payment provider (e.g. Stripe, Braintree).
/// </summary>
public interface IPaymentProvider
{
    Task<ChargeResult> CreateChargeAsync(string cardToken, decimal amount);
    Task<RefundResult> CreateRefundAsync(string chargeId);
    bool VerifySignature(string payload, string signature);
    string ParseEventType(string payload);
    Task HandleEventAsync(string eventType, string payload);
}

