using Moq;
using Payments;

namespace Payments.Tests;

[TestClass]
public class PaymentGatewayTests
{
    private Mock<IPaymentProvider> _providerMock = null!;
    private PaymentGateway _sut = null!;

    [TestInitialize]
    public void Setup()
    {
        _providerMock = new Mock<IPaymentProvider>(MockBehavior.Strict);
        _sut = new PaymentGateway(_providerMock.Object);
    }

    // ──────────────────────────────────────────────
    //  Constructor
    // ──────────────────────────────────────────────

    [TestMethod]
    public void Constructor_NullProvider_ThrowsArgumentNullException()
    {
        Assert.ThrowsException<ArgumentNullException>(() => new PaymentGateway(null!));
    }

    // ──────────────────────────────────────────────
    //  ChargeAsync — happy path
    // ──────────────────────────────────────────────

    [TestMethod]
    public async Task ChargeAsync_ValidInput_ReturnsSuccessfulCharge()
    {
        var expected = new ChargeResult("ch_123", Success: true);
        _providerMock
            .Setup(p => p.CreateChargeAsync("tok_visa", 49.99m))
            .ReturnsAsync(expected);

        var result = await _sut.ChargeAsync("tok_visa", 49.99m);

        Assert.AreEqual(expected.ChargeId, result.ChargeId);
        Assert.IsTrue(result.Success);
        _providerMock.Verify(p => p.CreateChargeAsync("tok_visa", 49.99m), Times.Once);
    }

    [TestMethod]
    public async Task ChargeAsync_ProviderDeclinesCard_ReturnsFailedCharge()
    {
        var expected = new ChargeResult("ch_456", Success: false);
        _providerMock
            .Setup(p => p.CreateChargeAsync("tok_declined", 100m))
            .ReturnsAsync(expected);

        var result = await _sut.ChargeAsync("tok_declined", 100m);

        Assert.IsFalse(result.Success);
    }

    [TestMethod]
    public async Task ChargeAsync_MinimumPositiveAmount_Succeeds()
    {
        var expected = new ChargeResult("ch_min", Success: true);
        _providerMock
            .Setup(p => p.CreateChargeAsync("tok_visa", 0.01m))
            .ReturnsAsync(expected);

        var result = await _sut.ChargeAsync("tok_visa", 0.01m);

        Assert.IsTrue(result.Success);
    }

    [TestMethod]
    public async Task ChargeAsync_LargeAmount_Succeeds()
    {
        var expected = new ChargeResult("ch_big", Success: true);
        _providerMock
            .Setup(p => p.CreateChargeAsync("tok_visa", 999_999.99m))
            .ReturnsAsync(expected);

        var result = await _sut.ChargeAsync("tok_visa", 999_999.99m);

        Assert.IsTrue(result.Success);
        Assert.AreEqual("ch_big", result.ChargeId);
    }

    // ──────────────────────────────────────────────
    //  ChargeAsync — input validation
    // ──────────────────────────────────────────────

    [TestMethod]
    public async Task ChargeAsync_NullCardToken_ThrowsArgumentException()
    {
        await Assert.ThrowsExceptionAsync<ArgumentException>(
            () => _sut.ChargeAsync(null!, 10m));
    }

    [TestMethod]
    public async Task ChargeAsync_EmptyCardToken_ThrowsArgumentException()
    {
        await Assert.ThrowsExceptionAsync<ArgumentException>(
            () => _sut.ChargeAsync("", 10m));
    }

    [TestMethod]
    public async Task ChargeAsync_WhitespaceCardToken_ThrowsArgumentException()
    {
        await Assert.ThrowsExceptionAsync<ArgumentException>(
            () => _sut.ChargeAsync("   ", 10m));
    }

    [TestMethod]
    public async Task ChargeAsync_ZeroAmount_ThrowsArgumentOutOfRangeException()
    {
        await Assert.ThrowsExceptionAsync<ArgumentOutOfRangeException>(
            () => _sut.ChargeAsync("tok_visa", 0m));
    }

    [TestMethod]
    public async Task ChargeAsync_NegativeAmount_ThrowsArgumentOutOfRangeException()
    {
        await Assert.ThrowsExceptionAsync<ArgumentOutOfRangeException>(
            () => _sut.ChargeAsync("tok_visa", -5m));
    }

    // ──────────────────────────────────────────────
    //  ChargeAsync — provider errors
    // ──────────────────────────────────────────────

    [TestMethod]
    public async Task ChargeAsync_ProviderThrows_ExceptionPropagates()
    {
        _providerMock
            .Setup(p => p.CreateChargeAsync(It.IsAny<string>(), It.IsAny<decimal>()))
            .ThrowsAsync(new HttpRequestException("Gateway timeout"));

        await Assert.ThrowsExceptionAsync<HttpRequestException>(
            () => _sut.ChargeAsync("tok_visa", 10m));
    }

    // ──────────────────────────────────────────────
    //  RefundAsync — happy path
    // ──────────────────────────────────────────────

    [TestMethod]
    public async Task RefundAsync_ValidChargeId_ReturnsSuccessfulRefund()
    {
        var expected = new RefundResult("re_789", Success: true);
        _providerMock
            .Setup(p => p.CreateRefundAsync("ch_123"))
            .ReturnsAsync(expected);

        var result = await _sut.RefundAsync("ch_123");

        Assert.AreEqual("re_789", result.RefundId);
        Assert.IsTrue(result.Success);
        _providerMock.Verify(p => p.CreateRefundAsync("ch_123"), Times.Once);
    }

    [TestMethod]
    public async Task RefundAsync_ProviderDeclinesRefund_ReturnsFailedRefund()
    {
        var expected = new RefundResult("re_000", Success: false);
        _providerMock
            .Setup(p => p.CreateRefundAsync("ch_old"))
            .ReturnsAsync(expected);

        var result = await _sut.RefundAsync("ch_old");

